import base64
import xml.etree.ElementTree as ET


class SAMLValidationError(Exception):
    pass


NS = {
    "samlp": "urn:oasis:names:tc:SAML:2.0:protocol",
    "saml": "urn:oasis:names:tc:SAML:2.0:assertion",
}


def decode_saml_response(encoded_response: str) -> str:
    try:
        return base64.b64decode(encoded_response).decode("utf-8")
    except Exception as exc:
        raise SAMLValidationError("Invalid base64 SAMLResponse") from exc


def parse_saml_response(xml_string: str) -> dict:
    try:
        root = ET.fromstring(xml_string)
    except ET.ParseError as exc:
        raise SAMLValidationError("Malformed XML") from exc

    if root.tag != f"{{{NS['samlp']}}}Response":
        raise SAMLValidationError("Root element must be samlp:Response")

    assertion = root.find("saml:Assertion", NS)
    if assertion is None:
        encrypted_assertion = root.find("saml:EncryptedAssertion", NS)
        if encrypted_assertion is not None:
            raise SAMLValidationError("EncryptedAssertion is not supported")
        raise SAMLValidationError("Missing saml:Assertion")

    subject = assertion.find("saml:Subject", NS)
    if subject is None:
        raise SAMLValidationError("Missing saml:Subject")

    nameid_el = subject.find("saml:NameID", NS)
    if nameid_el is None or not (nameid_el.text or "").strip():
        raise SAMLValidationError("Missing saml:NameID")

    name_id = nameid_el.text.strip()

    attr_stmt = assertion.find("saml:AttributeStatement", NS)
    attributes = {}

    if attr_stmt is not None:
        for attr in attr_stmt.findall("saml:Attribute", NS):
            attr_name = attr.attrib.get("Name") or attr.attrib.get("FriendlyName")
            if not attr_name:
                continue
            values = []
            for value_el in attr.findall("saml:AttributeValue", NS):
                value_text = "".join(value_el.itertext()).strip()
                if value_text:
                    values.append(value_text)
            if values:
                attributes[attr_name] = values

    issuer_el = root.find("saml:Issuer", NS)
    response_issuer = issuer_el.text.strip() if issuer_el is not None and issuer_el.text else None

    assertion_issuer_el = assertion.find("saml:Issuer", NS)
    assertion_issuer = assertion_issuer_el.text.strip() if assertion_issuer_el is not None and assertion_issuer_el.text else None

    conditions = assertion.find("saml:Conditions", NS)
    authn_statement = assertion.find("saml:AuthnStatement", NS)
    status_code = root.find("samlp:Status/samlp:StatusCode", NS)

    if status_code is None:
        raise SAMLValidationError("Missing samlp:StatusCode")

    status_value = status_code.attrib.get("Value")
    if status_value != "urn:oasis:names:tc:SAML:2.0:status:Success":
        raise SAMLValidationError(f"SAML status is not success: {status_value}")

    return {
        "name_id": name_id,
        "attributes": attributes,
        "response_issuer": response_issuer,
        "assertion_issuer": assertion_issuer,
        "has_conditions": conditions is not None,
        "has_authn_statement": authn_statement is not None,
    }


def get_first_attribute(attributes: dict, candidate_names: list[str]) -> str | None:
    for key in candidate_names:
        values = attributes.get(key)
        if values:
            return values[0]
    return None

