from django.conf import settings
from django.contrib.auth import get_user_model


def provision_user_from_saml(name_id: str, attributes: dict):
    User = get_user_model()
    config = getattr(settings, "SAML_SP", {})
    attr_map = config.get("ATTRIBUTE_MAP", {})
    create_unknown = config.get("CREATE_UNKNOWN_USERS", True)
    update_fields = config.get("UPDATE_USER_FIELDS", True)

    from .saml import get_first_attribute

    username = get_first_attribute(attributes, attr_map.get("username", [])) or name_id

    try:
        user = User.objects.get(username=username)
    except User.DoesNotExist:
        if not create_unknown:
            return None
        user = User(username=username)

    changed = False

    email = get_first_attribute(attributes, attr_map.get("email", []))
    first_name = get_first_attribute(attributes, attr_map.get("first_name", []))
    last_name = get_first_attribute(attributes, attr_map.get("last_name", []))

    if update_fields:
        if hasattr(user, "email") and email is not None and user.email != email:
            user.email = email
            changed = True
        if hasattr(user, "first_name") and first_name is not None and user.first_name != first_name:
            user.first_name = first_name
            changed = True
        if hasattr(user, "last_name") and last_name is not None and user.last_name != last_name:
            user.last_name = last_name
            changed = True

    if user.pk is None:
        user.set_unusable_password()
        changed = True

    if changed or user.pk is None:
        user.save()

    return user

# samlsp/views.py
from django.contrib.auth import login
from django.http import HttpResponseBadRequest, JsonResponse
from django.views.decorators.csrf import csrf_exempt
from django.views.decorators.http import require_POST

from .auth import provision_user_from_saml
from .saml import SAMLValidationError, decode_saml_response, parse_saml_response


@csrf_exempt
@require_POST
def saml_acs(request):
    saml_response = request.POST.get("SAMLResponse")
    if not saml_response:
        return HttpResponseBadRequest("Missing SAMLResponse")

    try:
        xml_string = decode_saml_response(saml_response)
        parsed = parse_saml_response(xml_string)
        user = provision_user_from_saml(parsed["name_id"], parsed["attributes"])
        if user is None:
            return HttpResponseBadRequest("User provisioning disabled or failed")
        login(request, user, backend="django.contrib.auth.backends.ModelBackend")
        request.session["saml_name_id"] = parsed["name_id"]
        request.session["saml_attributes"] = parsed["attributes"]
    except SAMLValidationError as exc:
        return HttpResponseBadRequest(str(exc))
    except Exception:
        return HttpResponseBadRequest("Failed to process SAML response")

    return JsonResponse(
        {
            "status": "ok",
            "user": user.get_username(),
            "name_id": parsed["name_id"],
            "attributes": parsed["attributes"],
        }
    )

# samlsp/tests.py
import base64

from django.contrib.auth import get_user_model
from django.test import Client, TestCase


def build_saml_response(name_id="john.doe", email="john@example.com", first_name="John", last_name="Doe"):
    xml = f"""
    <samlp:Response xmlns:samlp="urn:oasis:names:tc:SAML:2.0:protocol"
                    xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion">
      <saml:Issuer>https://idp.example.com</saml:Issuer>
      <samlp:Status>
        <samlp:StatusCode Value="urn:oasis:names:tc:SAML:2.0:status:Success"/>
      </samlp:Status>
      <saml:Assertion>
        <saml:Issuer>https://idp.example.com</saml:Issuer>
        <saml:Subject>
          <saml:NameID>{name_id}</saml:NameID>
        </saml:Subject>
        <saml:AuthnStatement/>
        <saml:AttributeStatement>
          <saml:Attribute Name="email">
            <saml:AttributeValue>{email}</saml:AttributeValue>
          </saml:Attribute>
          <saml:Attribute Name="first_name">
            <saml:AttributeValue>{first_name}</saml:AttributeValue>
          </saml:Attribute>
          <saml:Attribute Name="last_name">
            <saml:AttributeValue>{last_name}</saml:AttributeValue>
          </saml:Attribute>
        </saml:AttributeStatement>
      </saml:Assertion>
    </samlp:Response>
    """.strip()
    return base64.b64encode(xml.encode("utf-8")).decode("utf-8")


class SamlAcsTests(TestCase):
    def test_saml_acs_creates_user_and_session(self):
        client = Client()
        response = client.post("/saml/acs/", {"SAMLResponse": build_saml_response()})
        self.assertEqual(response.status_code, 200)

        User = get_user_model()
        user = User.objects.get(username="john.doe")
        self.assertEqual(user.email, "john@example.com")
        self.assertEqual(user.first_name, "John")
        self.assertEqual(user.last_name, "Doe")

        session = client.session
        self.assertEqual(session["saml_name_id"], "john.doe")
        self.assertIn("email", session["saml_attributes"])

    def test_rejects_invalid_xml(self):
        client = Client()
        bad = base64.b64encode(b"<nope>").decode("utf-8")
        response = client.post("/saml/acs/", {"SAMLResponse": bad})
        self.assertEqual(response.status_code, 400)